#!/usr/bin/env node

import yargs, { type Argv } from 'yargs';
import { hideBin } from 'yargs/helpers';
import { clients, Clients } from './cli/commands/install/clients';
import {
  paymentNetworks,
  paymentProtocols,
  requestMethodValues,
} from '@/shared/request/schemas/core';
import { MCP_VERSION } from '@/shared/version';
import {
  DESCRIPTIONS,
  TOOL_PARAMS,
  buildServerInstructions,
} from '@/shared/descriptions';
import { loadUserOrigins } from '@/shared/user-origins';
import { randomBytes } from 'crypto';
import type { GlobalFlags } from './types';

const isClaudeCode = Boolean(process.env.CLAUDECODE);
const defaultYes = isClaudeCode || Boolean(process.env.CI);

const configureFetchCommand = (
  command: Argv<GlobalFlags>,
  params: typeof TOOL_PARAMS.fetch,
  epilogue: string
) =>
  command
    .positional('url', {
      type: 'string',
      description: params.url,
      demandOption: true,
    })
    .option('method', {
      alias: 'm',
      type: 'string',
      description: params.method,
      choices: requestMethodValues,
    })
    .option('body', {
      alias: 'b',
      type: 'string',
      description: params.body,
    })
    .option('headers', {
      alias: ['H', 'header'],
      type: 'string',
      array: true,
      description: params.headers,
    })
    .option('timeout', {
      type: 'number',
      description: params.timeout,
    })
    .option('payment-protocol', {
      alias: 'p',
      type: 'string',
      description: params.paymentProtocol,
      choices: paymentProtocols,
    })
    .option('payment-network', {
      type: 'string',
      description: params.paymentNetwork,
      choices: paymentNetworks,
    })
    .option('max-amount', {
      type: 'number',
      description: params.maxAmount,
    })
    .epilogue(epilogue);

void yargs(hideBin(process.argv))
  .scriptName('agentcash')
  .usage('$0 [command] [options]')
  .option('dev', {
    type: 'boolean',
    description: 'Enable dev mode (use localhost endpoints)',
    default: false,
  })
  .option('invite', {
    type: 'string',
    description: 'Invite code to redeem for starter money',
    required: false,
  })
  .option('yes', {
    alias: 'y',
    type: 'boolean',
    description: 'Yes to all prompts',
    default: defaultYes ? true : undefined,
  })
  .option('sessionId', {
    type: 'string',
    description:
      'Session ID for matching requests (auto-generated if not provided)',
    required: false,
    default: randomBytes(16).toString('hex'),
  })
  .option('provider', {
    type: 'string',
    description: 'Provider to use for the MCP server',
    required: false,
    default: `agentcash@${MCP_VERSION}`,
  })
  .option('format', {
    type: 'string',
    description:
      'Output format: json (default for pipes) or pretty (default for TTY)',
    choices: ['json', 'pretty'] as const,
    default: process.stdout.isTTY ? ('pretty' as const) : ('json' as const),
  })
  .option('quiet', {
    alias: 'q',
    type: 'boolean',
    description: 'Suppress stderr output',
    default: false,
  })
  .option('verbose', {
    alias: 'v',
    type: 'boolean',
    description: 'Enable verbose logging (debug output to stderr)',
    default: false,
  })
  .middleware(async argv => {
    // Configure CLI context for shared modules (like logging)
    if (argv.verbose) {
      const { configureCliContext } = await import('@/cli/lib/context');
      configureCliContext({ verbose: true });
    }
  })
  // ============================================================
  // Core CLI Commands (for agent/programmatic use)
  // ============================================================
  .command(
    'fetch <url>',
    DESCRIPTIONS.fetch.cli,
    yargs =>
      configureFetchCommand(
        yargs,
        TOOL_PARAMS.fetch,
        DESCRIPTIONS.fetch.epilogue
      ),
    async args => {
      const { fetchCommand } = await import('@/cli/commands/fetch');
      await fetchCommand(args);
    }
  )
  .command(
    'fetch-auth <url>',
    DESCRIPTIONS.fetchWithAuth.cli,
    yargs =>
      configureFetchCommand(
        yargs,
        TOOL_PARAMS.fetchWithAuth,
        DESCRIPTIONS.fetchWithAuth.epilogue
      ),
    async args => {
      const { fetchCommand } = await import('@/cli/commands/fetch');
      await fetchCommand(args);
    }
  )
  .command(
    'check <url>',
    DESCRIPTIONS.checkEndpointSchema.cli,
    yargs =>
      yargs
        .positional('url', {
          type: 'string',
          description: TOOL_PARAMS.checkEndpointSchema.url,
          demandOption: true,
        })
        .option('method', {
          alias: 'm',
          type: 'string',
          description: TOOL_PARAMS.checkEndpointSchema.method,
          choices: requestMethodValues,
        })
        .option('body', {
          alias: 'b',
          type: 'string',
          description: TOOL_PARAMS.checkEndpointSchema.body,
        })
        .option('headers', {
          alias: ['H', 'header'],
          type: 'string',
          array: true,
          description: TOOL_PARAMS.checkEndpointSchema.headers,
        })
        .epilogue(DESCRIPTIONS.checkEndpointSchema.epilogue),
    async args => {
      const { checkCommand } = await import('@/cli/commands/check');
      await checkCommand({
        ...args,
        url: args.url,
        method: args.method,
        body: args.body,
        headers: args.headers,
      });
    }
  )
  .command(
    'try <url>',
    DESCRIPTIONS.try.cli,
    yargs =>
      yargs.positional('url', {
        type: 'string',
        description: TOOL_PARAMS.try.url,
        demandOption: true,
      }),
    async args => {
      const { tryCommand } = await import('@/cli/commands/try');
      await tryCommand(args);
    }
  )
  .command(
    'search <query>',
    DESCRIPTIONS.search.cli,
    yargs =>
      yargs
        .positional('query', {
          type: 'string',
          description: TOOL_PARAMS.search.query,
          demandOption: true,
        })
        .option('broad', {
          type: 'boolean',
          description: TOOL_PARAMS.search.broad,
          default: false,
        })
        .option('limit', {
          type: 'number',
          description: TOOL_PARAMS.search.limit,
        })
        .option('page', {
          type: 'number',
          description: TOOL_PARAMS.search.page,
        }),
    async args => {
      const { searchCommand } = await import('@/cli/commands/search');
      await searchCommand(args);
    }
  )
  .command(
    'discover <url>',
    DESCRIPTIONS.discoverApiEndpoints.cli,
    yargs =>
      yargs
        .positional('url', {
          type: 'string',
          description: TOOL_PARAMS.discoverApiEndpoints.url,
          demandOption: true,
        })
        .option('include-guidance', {
          type: 'boolean',
          description: TOOL_PARAMS.discoverApiEndpoints.includeGuidance,
        })
        .epilogue(DESCRIPTIONS.discoverApiEndpoints.epilogue),
    async args => {
      const { discoverCommand } = await import('@/cli/commands/discover');
      await discoverCommand(args);
    }
  )
  .command(
    'register <url>',
    'Register an origin with agentcash (discover + index endpoints)',
    yargs =>
      yargs.positional('url', {
        type: 'string',
        description: 'The origin URL to register',
        demandOption: true,
      }),
    async args => {
      const { registerCommand } = await import('@/cli/commands/register');
      await registerCommand(args);
    }
  )
  .command(
    'add <url>',
    'Add an origin and install its skill to agent clients. The origin is added to the MCP server description.',
    yargs =>
      yargs.positional('url', {
        type: 'string',
        description: TOOL_PARAMS.add.url,
        demandOption: true,
      }),
    async args => {
      const { addSkillCommand } = await import('@/cli/commands/add-skill');
      await addSkillCommand(args);
    }
  )
  .command(
    'origins',
    'Manage registered origins',
    yargs =>
      yargs
        .command(
          'add <url>',
          'Add an origin to agent clients. The origin is added to the MCP server description.',
          yargs =>
            yargs.positional('url', {
              type: 'string',
              description: 'The origin URL to register',
              demandOption: true,
            }),
          async args => {
            const { originsAddCommand } =
              await import('@/cli/commands/origins');
            await originsAddCommand(args);
          }
        )
        .command(
          'list',
          'List all registered origins',
          yargs => yargs,
          async args => {
            const { originsListCommand } =
              await import('@/cli/commands/origins');
            await originsListCommand(args);
          }
        )
        .command(
          'remove <url>',
          'Remove a user-added origin',
          yargs =>
            yargs.positional('url', {
              type: 'string',
              description: 'The origin URL to remove',
              demandOption: true,
            }),
          async args => {
            const { originsRemoveCommand } =
              await import('@/cli/commands/origins');
            await originsRemoveCommand(args);
          }
        )
        .demandCommand(1, 'You must specify an origins subcommand')
        .strict(),
    () => {
      // Show help for origins command
    }
  )
  .command(
    'onboard [code]',
    'Non-interactive onboarding flow for agentcash wallet + MCP setup',
    yargs =>
      yargs.positional('code', {
        type: 'string',
        description: 'The invite code to redeem (optional)',
      }),
    async args => {
      const { onboardCommand } = await import('@/cli/commands/onboard');
      await onboardCommand({ ...args, code: args.code ?? args.invite });
    }
  )
  .command(
    'wallet',
    'Deprecated wallet command aliases',
    yargs =>
      yargs
        .command(
          'info',
          "Deprecated alias. Prints migration guidance for 'balance' and 'accounts'.",
          yargs => yargs,
          async args => {
            const { legacyWalletInfoCommand } =
              await import('@/cli/commands/wallet');
            await legacyWalletInfoCommand(args);
          }
        )
        .command(
          'balance',
          "Deprecated alias. Prints migration guidance for 'balance'.",
          yargs => yargs,
          async args => {
            const { legacyWalletBalanceCommand } =
              await import('@/cli/commands/wallet');
            await legacyWalletBalanceCommand(args);
          }
        )
        .command(
          'redeem <code>',
          "Deprecated alias. Prints migration guidance for 'redeem <code>'.",
          yargs =>
            yargs.positional('code', {
              type: 'string',
              description: TOOL_PARAMS.redeemInvite.code,
              demandOption: true,
            }),
          async args => {
            const { legacyWalletRedeemCommand } =
              await import('@/cli/commands/wallet');
            await legacyWalletRedeemCommand(args);
          }
        )
        .command(
          'address',
          'Deprecated alias for wallet address lookup.',
          yargs => yargs,
          async args => {
            const { legacyWalletAddressCommand } =
              await import('@/cli/commands/wallet');
            await legacyWalletAddressCommand(args);
          }
        )
        .demandCommand(1, 'You must specify a wallet subcommand')
        .strict(),
    () => {
      // Show help for wallet command
    }
  )
  .command(
    'balance',
    DESCRIPTIONS.getBalance.cli,
    yargs => yargs,
    async args => {
      const { getBalanceCommand } = await import('@/cli/commands/wallet');
      await getBalanceCommand(args);
    }
  )
  .command(
    'accounts',
    DESCRIPTIONS.listAccounts.cli,
    yargs => yargs,
    async args => {
      const { listAccountsCommand } = await import('@/cli/commands/wallet');
      await listAccountsCommand(args);
    }
  )
  .command(
    'redeem <code>',
    DESCRIPTIONS.redeemInvite.cli,
    yargs =>
      yargs.positional('code', {
        type: 'string',
        description: TOOL_PARAMS.redeemInvite.code,
        demandOption: true,
      }),
    async args => {
      const { walletRedeemCommand } = await import('@/cli/commands/wallet');
      await walletRedeemCommand(args);
    }
  )
  .command(
    'settings',
    'View and update user settings',
    yargs =>
      yargs
        .command(
          'get',
          'Show current settings',
          yargs => yargs,
          async args => {
            const { settingsGetCommand } =
              await import('@/cli/commands/settings');
            await settingsGetCommand(args);
          }
        )
        .command(
          'set <key> <value>',
          'Update a setting (e.g. settings set maxAmount 10)',
          yargs =>
            yargs
              .positional('key', {
                type: 'string',
                description: 'Setting name (e.g. maxAmount)',
                demandOption: true,
              })
              .positional('value', {
                type: 'string',
                description: 'Setting value',
                demandOption: true,
              }),
          async args => {
            const { settingsSetCommand } =
              await import('@/cli/commands/settings');
            await settingsSetCommand(args);
          }
        )
        .demandCommand(1, 'You must specify a settings subcommand')
        .strict(),
    () => {
      // Show help for settings command
    }
  )
  .command(
    'report-error',
    DESCRIPTIONS.reportError.cli,
    yargs =>
      yargs
        .option('tool', {
          type: 'string',
          description: TOOL_PARAMS.reportError.tool,
          demandOption: true,
        })
        .option('summary', {
          type: 'string',
          description: TOOL_PARAMS.reportError.summary,
          demandOption: true,
        })
        .option('error-message', {
          type: 'string',
          description: TOOL_PARAMS.reportError.errorMessage,
          demandOption: true,
        })
        .option('resource', {
          type: 'string',
          description: TOOL_PARAMS.reportError.resource,
        })
        .option('stack', {
          type: 'string',
          description: TOOL_PARAMS.reportError.stack,
        })
        .option('full-report', {
          type: 'string',
          description: TOOL_PARAMS.reportError.fullReport,
        }),
    async args => {
      const { reportErrorCommand } =
        await import('@/cli/commands/report-error');
      await reportErrorCommand(args);
    }
  )
  .command(
    DESCRIPTIONS.bridge.toolNames.cli,
    DESCRIPTIONS.bridge.cli,
    yargs =>
      yargs
        .option('from', {
          type: 'string',
          description: TOOL_PARAMS.bridge.from,
          choices: paymentNetworks,
          required: true,
        })
        .option('to', {
          type: 'string',
          description: TOOL_PARAMS.bridge.to,
          choices: paymentNetworks,
          required: true,
        })
        .option('amount', {
          type: 'number',
          description: TOOL_PARAMS.bridge.amount,
          required: true,
        }),
    async args => {
      const { bridgeCommand } = await import('@/cli/commands/bridge');
      await bridgeCommand(args);
    }
  )
  // ============================================================
  // Server & Installation Commands
  // ============================================================
  .command(
    ['$0', 'server'],
    'Start the MCP server (default when no command specified)',
    yargs => yargs,
    async args => {
      const { serverCommand } = await import('@/cli/commands/server');
      await serverCommand(args);
    }
  )
  .command(
    'install',
    'Install the MCP server configuration for a client',
    yargs =>
      yargs.option('client', {
        type: 'string',
        description: 'The client name',
        choices: clients,
        required: false,
        default: isClaudeCode ? Clients.ClaudeCode : undefined,
      }),
    async args => {
      const { installMcpServer } = await import('@/cli/commands/install');
      await installMcpServer(args);
    }
  )
  .command(
    'fund',
    'Open the funding page to add USDC to your wallet',
    yargs => yargs,
    async args => {
      const { fundMcpServer } = await import('@/cli/commands/fund');
      await fundMcpServer(args);
    }
  )
  .example(
    '$0 fetch "https://stableenrich.dev/api/apollo/people-enrich" -m POST -b \'{"email":"user@example.com"}\'',
    'Fetch with x402 payment'
  )
  .example(
    '$0 check "https://stableenrich.dev/api/apollo/people-enrich"',
    'Check endpoint pricing'
  )
  .example(
    '$0 discover "https://stableenrich.dev"',
    'Discover endpoints on origin'
  )
  .example(
    '$0 register "https://stableenrich.dev"',
    'Register origin with agentcash'
  )
  .example(
    '$0 onboard ABC123',
    'Install onboarding skill, configure MCP, and redeem an invite'
  )
  .example('$0 search "flight data"', 'Search for APIs by description')
  .example('$0 balance', 'Get wallet balance')
  .example('$0 accounts', 'List wallet accounts by network')
  .example('$0 redeem ABC123', 'Redeem invite code')
  .example('$0', 'Start MCP server (default)')
  .example('$0 install --client cursor', 'Install MCP for Cursor')
  .strict()
  .epilogue(buildServerInstructions(loadUserOrigins()))
  .help()
  .version(MCP_VERSION)
  .parseAsync()
  .catch(err => {
    // Output error in JSON format for agent consumption
    const response = {
      success: false,
      error: {
        code: 'GENERAL_ERROR',
        message: err instanceof Error ? err.message : String(err),
        surface: 'cli',
        cause: 'unknown',
      },
    };
    console.log(JSON.stringify(response, null, 2));
    process.exit(1);
  });
